import java.util.ArrayList;
import java.util.List;

public List<Integer> findGoodIndices(int[] nums, int k) {
    List<Integer> goodIndices = new ArrayList<>();
    for (int i = k; i < nums.length - k; i++) {
        boolean leftNonInc = true;
        boolean rightNonDec = true;

        for (int j = 0; j < k - 1; j++) {
            if (nums[i - j - 1] < nums[i - j - 2]) {
                leftNonInc = false;
                break;
            }
        }

        for (int j = 0; j < k - 1; j++) {
            if (nums[i + j + 1] < nums[i + j + 2]) {
                rightNonDec = false;
                break;
            }
        }

        if (leftNonInc && rightNonDec) {
            goodIndices.add(i);
        }
    }
    return goodIndices;
}
